import { writeFileSync } from 'node:fs';

import { fetchRollbarErrors } from './rollbar-client';
import { Digest } from './types';

async function run(): Promise<void> {
	const rollbarToken = process.env['ROLLBAR_READ_TOKEN'];

	if (!rollbarToken) {
		throw new Error('ROLLBAR_READ_TOKEN is required');
	}

	console.log('Fetching Rollbar errors (last 24h)...');
	const errors = await fetchRollbarErrors({ readToken: rollbarToken });
	console.log(`Fetched ${errors.length} active error items from Rollbar`);

	const newItemsCount = errors.filter((e) => e.isNew).length;

	const digest: Digest = {
		generatedAt: new Date().toISOString(),
		rollbar: {
			totalItemsActive24h: errors.length,
			newItemsCount,
		},
		errors,
	};

	writeFileSync('rollbar-digest.json', JSON.stringify(digest, null, 2));
	console.log('Digest written to rollbar-digest.json');
	console.log(`Total active items: ${errors.length}, new in 24h: ${newItemsCount}`);
}

run().catch((err: unknown) => {
	console.error('Monitor script failed:', err);
	process.exit(1);
});
